import{_ as t,o as a,c as i,ai as r}from"./chunks/framework.C3UwiwZw.js";const p=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"SecureWeb","text":"Build websites that can't be broken.","tagline":"A practical, beginner-friendly guide to web security — from first line of code to production deployment.","image":{"src":"/logo.svg","alt":"SecureWeb Shield Logo"},"actions":[{"theme":"brand","text":"Start Learning →","link":"/getting-started"},{"theme":"alt","text":"View on GitHub","link":"https://github.com"}]},"features":[{"icon":"🗺️","title":"Threat Modeling First","details":"Learn to think like an attacker before writing a single line of code. Identify your assets, enumerate your attack surfaces, and plan your defenses from day one.","link":"/getting-started","linkText":"Read Chapter 1"},{"icon":"🔐","title":"HTTPS & Transport Security","details":"Set up TLS certificates, enforce HTTPS redirects, and implement HSTS so browsers never allow an insecure connection to your domain again.","link":"/https-and-transport","linkText":"Read Chapter 2"},{"icon":"🧑‍💻","title":"Authentication & Passwords","details":"Hash and salt passwords correctly, implement multi-factor authentication, and manage sessions without opening yourself up to hijacking attacks.","link":"/authentication","linkText":"Read Chapter 3"},{"icon":"🧹","title":"Input Validation & Sanitization","details":"Block XSS, SQL injection, and CSRF at the gate. Learn why you should never trust user input and how to sanitize it safely on both client and server.","link":"/input-validation","linkText":"Read Chapter 4"},{"icon":"🛡️","title":"Security Headers & CSP","details":"Configure Content Security Policy, X-Frame-Options, and a full suite of HTTP response headers that harden your site against a wide class of attacks.","link":"/security-headers","linkText":"Read Chapter 5"},{"icon":"🔑","title":"Secrets & Environment Config","details":"Keep API keys, database credentials, and tokens out of your source code. Learn about .env files, secret vaults, and proper key rotation strategies.","link":"/secrets-and-env","linkText":"Read Chapter 6"},{"icon":"📦","title":"Dependency Security","details":"Your app is only as secure as its weakest package. Learn how to audit dependencies, respond to CVEs, and defend against supply chain attacks.","link":"/dependencies","linkText":"Read Chapter 7"},{"icon":"🧪","title":"Testing & Auditing","details":"Run automated vulnerability scans, write security-focused tests, and learn the basics of penetration testing so you can find your own flaws before attackers do.","link":"/testing-and-auditing","linkText":"Read Chapter 8"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}`),n={name:"index.md"};function o(s,e,d,l,c,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<div class="vp-doc" style="max-width:960px;margin:0 auto;padding:64px 24px;"><h2 id="why-this-guide" tabindex="-1">Why This Guide? <a class="header-anchor" href="#why-this-guide" aria-label="Permalink to “Why This Guide?”">​</a></h2><p>The internet is full of security advice that&#39;s either <strong>too vague</strong> (&quot;just sanitize your inputs!&quot;) or <strong>too advanced</strong> for developers who are still learning the ropes. This guide aims to be different.</p><p>Every chapter is:</p><ul><li><strong>Practical</strong> — real code you can copy, adapt, and deploy.</li><li><strong>Explained</strong> — we don&#39;t just show you <em>what</em> to do, but <em>why</em> it matters.</li><li><strong>Progressive</strong> — chapters build on each other, so nothing comes out of nowhere.</li></ul><p>Whether you&#39;re a student building your first project or a professional who wants to close knowledge gaps, you&#39;ll find something useful here.</p><hr><h2 id="what-you-ll-build" tabindex="-1">What You&#39;ll Build <a class="header-anchor" href="#what-you-ll-build" aria-label="Permalink to “What You&#39;ll Build”">​</a></h2><p>Throughout the series you&#39;ll harden a real Express.js application, adding security layer by layer. By the final chapter, your app will have:</p><table tabindex="0"><thead><tr><th>Layer</th><th>What&#39;s Protected</th></tr></thead><tbody><tr><td>🌐 Transport</td><td>HTTPS, HSTS, TLS configuration</td></tr><tr><td>🔐 Authentication</td><td>Bcrypt hashing, JWT, MFA</td></tr><tr><td>🧹 Input handling</td><td>XSS, SQLi, CSRF protection</td></tr><tr><td>🛡️ HTTP headers</td><td>CSP, X-Frame-Options, CORP, COOP</td></tr><tr><td>🔑 Secrets</td><td>Vault-managed env config, key rotation</td></tr><tr><td>📦 Dependencies</td><td>Automated auditing, lockfile hygiene</td></tr><tr><td>🧪 Testing</td><td>DAST scans, security unit tests</td></tr></tbody></table><hr><h2 id="based-on-industry-standards" tabindex="-1">Based on Industry Standards <a class="header-anchor" href="#based-on-industry-standards" aria-label="Permalink to “Based on Industry Standards”">​</a></h2><p>This guide is grounded in widely accepted security frameworks and references, including:</p><ul><li><a href="https://owasp.org/www-project-top-ten/" target="_blank" rel="noreferrer"><strong>OWASP Top 10</strong></a> — The definitive list of the most critical web application security risks.</li><li><a href="https://www.nist.gov/cyberframework" target="_blank" rel="noreferrer"><strong>NIST Cybersecurity Framework</strong></a> — A structured approach to managing security risk.</li><li><a href="https://infosec.mozilla.org/guidelines/web_security" target="_blank" rel="noreferrer"><strong>Mozilla Web Security Guidelines</strong></a> — Practical, opinionated recommendations from Mozilla&#39;s security team.</li></ul><hr><h2 id="ready-to-start" tabindex="-1">Ready to Start? <a class="header-anchor" href="#ready-to-start" aria-label="Permalink to “Ready to Start?”">​</a></h2><div style="margin-top:32px;display:flex;gap:16px;flex-wrap:wrap;"><a href="/getting-started" style="display:inline-block;background:var(--vp-c-brand-1);color:white;padding:12px 28px;border-radius:8px;font-weight:600;text-decoration:none;font-size:1rem;"> Chapter 1: Getting Started → </a><a href="/getting-started#series-overview" style="display:inline-block;background:var(--vp-c-default-soft);color:var(--vp-c-text-1);padding:12px 28px;border-radius:8px;font-weight:600;text-decoration:none;font-size:1rem;"> View Full Series </a></div></div>',1)])])}const g=t(n,[["render",o]]);export{p as __pageData,g as default};
